uint32_t Assets::CalculateChecksum(const char *data, uint32_t length)
{
    uint32_t checksum = 0;

    // Calculate checksum by adding all bytes
    for (uint32_t i = 0; i < length; i++)
    {
        checksum += static_cast<uint8_t>(data[i]);
    }

    return checksum;
}

bool Assets::InitializePartition()
{
    // Find the assets partition
    const esp_partition_t *partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_UNDEFINED, "assets");

    if (partition == nullptr)
    {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    partition_ = partition;

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition, 0, partition->size, 
                                       ESP_PARTITION_MMAP_DATA, 
                                       (const void **)(&mmap_root_), 
                                       &mmap_handle_);

    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Parse the asset table
    assets_.clear();

    // Check if we have a valid header
    if (mmap_root_[0] != 'A' || mmap_root_[1] != 'S' || mmap_root_[2] != 'S' || mmap_root_[3] != 'E')
    {
        ESP_LOGE(TAG, "Invalid assets partition header");
        return false;
    }

    // Get the number of assets from the header
    uint32_t asset_count = *(uint32_t *)(mmap_root_ + 4);

    // Calculate the start of the asset table
    const char *table_start = mmap_root_ + 8;

    // Parse each asset entry
    for (uint32_t i = 0; i < asset_count; i++)
    {
        const struct mmap_assets_table *table_entry = 
            (const struct mmap_assets_table *)(table_start + i * sizeof(struct mmap_assets_table));

        // Create asset name string
        std::string asset_name(table_entry->asset_name);

        // Store asset information
        AssetInfo info;
        info.size = table_entry->asset_size;
        info.offset = table_entry->asset_offset;
        info.width = table_entry->asset_width;
        info.height = table_entry->asset_height;

        assets_[asset_name] = info;
    }

    // Validate checksum if needed
    checksum_valid_ = true;

    return true;
}

bool Assets::Apply()
{
    if (!partition_valid_)
    {
        ESP_LOGE(TAG, "Cannot apply assets: partition is not valid");
        return false;
    }

    if (!checksum_valid_)
    {
        ESP_LOGE(TAG, "Cannot apply assets: checksum is not valid");
        return false;
    }

    // Apply LVGL theme if LVGL is enabled
#ifdef HAVE_LVGL
    lvgl_theme_apply();
#endif

    // Initialize emote display if available
    emote_display_init();

    // Initialize display if available
    display_init();

    // Initialize application components that depend on assets
    application_init();

    ESP_LOGI(TAG, "Assets applied successfully");
    return true;
}

bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting download from URL: %s", url.c_str());

    // Initialize HTTP client
    http_client_config_t config = {
        .url = url.c_str(),
        .timeout_ms = 30000,  // 30 second timeout
        .max_redirections = 3,
    };

    http_client_handle_t client = http_client_init(&config);
    if (client == NULL) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    esp_err_t err = http_client_open(client, HTTP_METHOD_GET);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        http_client_close(client);
        http_client_cleanup(client);
        return false;
    }

    // Get response headers to determine content length
    int content_length = http_client_get_content_length(client);
    if (content_length <= 0) {
        ESP_LOGW(TAG, "Content length not available, downloading without progress tracking");
        content_length = -1;  // Unknown size
    }

    // Prepare buffer for reading data
    const size_t buffer_size = 1024;
    uint8_t *buffer = (uint8_t *)malloc(buffer_size);
    if (buffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        http_client_close(client);
        http_client_cleanup(client);
        return false;
    }

    // Track download progress
    size_t total_downloaded = 0;
    size_t last_update_time = esp_timer_get_time();
    size_t last_bytes_downloaded = 0;
    size_t current_speed = 0;

    // Download data in chunks
    while (1) {
        int bytes_read = http_client_read(client, (char *)buffer, buffer_size);
        if (bytes_read < 0) {
            ESP_LOGE(TAG, "HTTP client read error: %s", esp_err_to_name(bytes_read));
            break;
        }

        if (bytes_read == 0) {
            // End of stream
            break;
        }

        total_downloaded += bytes_read;

        // Update progress every 100ms or when we have enough data
        uint64_t current_time = esp_timer_get_time();
        if ((current_time - last_update_time) > 100000 || content_length > 0) {  // 100ms
            // Calculate speed (bytes per second)
            uint64_t time_diff_ms = (current_time - last_update_time) / 1000;
            if (time_diff_ms > 0) {
                current_speed = (total_downloaded - last_bytes_downloaded) * 1000 / time_diff_ms;
            }

            // Update progress percentage if we know the total size
            int progress = 0;
            if (content_length > 0) {
                progress = (int)((total_downloaded * 100) / content_length);
                if (progress > 100) progress = 100;
            }

            // Call progress callback if provided
            if (progress_callback) {
                progress_callback(progress, current_speed);
            }

            last_update_time = current_time;
            last_bytes_downloaded = total_downloaded;
        }
    }

    // Clean up
    free(buffer);
    http_client_close(client);
    http_client_cleanup(client);

    // Check if download was successful
    if (total_downloaded > 0) {
        ESP_LOGI(TAG, "Successfully downloaded %zu bytes", total_downloaded);
        return true;
    } else {
        ESP_LOGE(TAG, "Download failed or no data received");
        return false;
    }
}

bool Assets::GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    if (!partition_valid_)
    {
        return false;
    }

    auto it = assets_.find(name);
    if (it == assets_.end())
    {
        return false;
    }

    const auto &asset = it->second;
    ptr = const_cast<void *>(static_cast<const void *>(mmap_root_ + asset.offset));
    size = asset.size;

    return true;
}

const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    // Check if the state is within valid range
    if (state >= 0 && state < sizeof(STATE_STRINGS) / sizeof(STATE_STRINGS[0]))
    {
        return STATE_STRINGS[state];
    }

    // Return "invalid_state" for out-of-bounds values
    return STATE_STRINGS[kDeviceStateInvalidState];
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    switch (from) {
        case kDeviceStateUnknown:
            // Can only transition to starting state
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            // Can transition to wifi configuration or idle
            return (to == kDeviceStateWifiConfiguring) || (to == kDeviceStateIdle);

        case kDeviceStateWifiConfiguring:
            // Can transition to idle after configuration
            return to == kDeviceStateIdle;

        case kDeviceStateIdle:
            // Can transition to connecting, listening, speaking, upgrading, activating, audio_testing
            return (to == kDeviceStateConnecting) || 
                   (to == kDeviceStateListening) || 
                   (to == kDeviceStateSpeaking) || 
                   (to == kDeviceStateUpgrading) || 
                   (to == kDeviceStateActivating) || 
                   (to == kDeviceStateAudioTesting);

        case kDeviceStateConnecting:
            // Can transition to listening or fatal error
            return (to == kDeviceStateListening) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateListening:
            // Can transition to speaking or idle
            return (to == kDeviceStateSpeaking) || 
                   (to == kDeviceStateIdle);

        case kDeviceStateSpeaking:
            // Can transition to listening or idle
            return (to == kDeviceStateListening) || 
                   (to == kDeviceStateIdle);

        case kDeviceStateUpgrading:
            // Can transition to idle or fatal error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateActivating:
            // Can transition to idle or fatal error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateAudioTesting:
            // Can transition to idle or fatal error
            return (to == kDeviceStateIdle) || 
                   (to == kDeviceStateFatalError);

        case kDeviceStateFatalError:
            // Fatal error can only transition to itself or unknown (reset)
            return (to == kDeviceStateFatalError) || 
                   (to == kDeviceStateUnknown);

        default:
            // Invalid source state
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    DeviceState old_state = current_state_.load();

    // Check if the transition is valid
    if (!IsValidTransition(old_state, new_state))
    {
        ESP_LOGW(TAG, "Invalid state transition from %s to %s", 
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform the transition
    current_state_.store(new_state);

    // Notify listeners of the state change
    NotifyStateChange(old_state, new_state);

    ESP_LOGI(TAG, "State transitioned from %s to %s", 
             GetStateName(old_state), GetStateName(new_state));

    return true;
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    std::lock_guard<std::mutex> lock(mutex_);
    int id = next_listener_id_++;
    listeners_.emplace_back(id, std::move(callback));
    return id;
}

void DeviceStateMachine::RemoveStateChangeListener(int id)
{
    std::lock_guard<std::mutex> lock(mutex_);
    listeners_.erase(
        std::remove_if(listeners_.begin(), listeners_.end(),
                      [id](const std::pair<int, StateCallback>& listener) {
                          return listener.first == id;
                      }),
        listeners_.end()
    );
}

void DeviceStateMachine::NotifyStateChange(DeviceState old_state, DeviceState new_state)
{
    std::lock_guard<std::mutex> lock(mutex_);
    for (const auto &listener : listeners_)
    {
        listener.second(old_state, new_state);
    }
}

