auto Ota::SetupHttp()
{
    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(0);
    auto user_agent = SystemInfo::GetUserAgent();
    http->SetHeader("Activation-Version", has_serial_number_ ? "2" : "1");
    http->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    http->SetHeader("Client-Id", Board::GetInstance().GetUuid());
    if (has_serial_number_)
    {
        http->SetHeader("Serial-Number", serial_number_.c_str());
        ESP_LOGI(TAG, "Setup HTTP, User-Agent: %s, Serial-Number: %s", user_agent.c_str(), serial_number_.c_str());
    }
    http->SetHeader("User-Agent", user_agent);
    http->SetHeader("Accept-Language", Lang::CODE);
    http->SetHeader("Content-Type", "application/json");

    return http;
}

esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.back() != '/')
    {
        url += "/";
    }
    url += "version";

    auto http = SetupHttp();

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection for version check");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to check version, status code: %d", status_code);
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response from version check");
        return ESP_FAIL;
    }

    cJSON *json = cJSON_Parse(response.c_str());
    if (!json)
    {
        ESP_LOGE(TAG, "Failed to parse version response JSON");
        return ESP_FAIL;
    }

    cJSON *version = cJSON_GetObjectItem(json, "version");
    cJSON *url_item = cJSON_GetObjectItem(json, "url");
    cJSON *challenge = cJSON_GetObjectItem(json, "challenge");

    if (!version || !url_item)
    {
        ESP_LOGE(TAG, "Missing required fields in version response");
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    std::string new_version = cJSON_GetStringValue(version);
    std::string firmware_url = cJSON_GetStringValue(url_item);

    if (new_version.empty() || firmware_url.empty())
    {
        ESP_LOGE(TAG, "Invalid version or URL in response");
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    // Check if we have activation challenge
    if (challenge && has_serial_number_)
    {
        activation_challenge_ = cJSON_GetStringValue(challenge);
        has_activation_challenge_ = true;
    }

    // Check if new version is available
    auto current_version = esp_app_get_description()->version;
    if (IsNewVersionAvailable(current_version, new_version))
    {
        ESP_LOGI(TAG, "New version available: %s -> %s", current_version, new_version.c_str());
        firmware_url_ = firmware_url;
        cJSON_Delete(json);
        return ESP_OK;
    }

    ESP_LOGI(TAG, "Current version is up to date: %s", current_version);
    cJSON_Delete(json);
    return ESP_ERR_NOT_FOUND;
}

void Ota::MarkCurrentVersionValid()
{
