    const esp_partition_t *running_partition = esp_ota_get_running_partition();
    if (running_partition == NULL)
    {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Set the running partition as the boot partition to mark current version as valid
    esp_err_t err = esp_ota_set_boot_partition(running_partition);
    if (err != ESP_OK)
    {
