    ESP_LOGI(TAG, "Current version marked as valid");
}

bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    ESP_LOGI(TAG, "Starting firmware upgrade from %s", firmware_url.c_str());

    // Initialize OTA
    esp_err_t err = esp_ota_begin(esp_ota_get_next_update_partition(NULL), OTA_SIZE_UNKNOWN, &update_handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_begin failed: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA begin successful, handle: %p", update_handle_);

    // Create HTTP client
    auto http = SetupHttp();
    http->SetContent("");

    if (!http->Open("GET", firmware_url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection for firmware download");
        esp_ota_end(update_handle_);
        return false;
    }

    // Get content length for progress tracking
    size_t content_length = http->GetContentLength();
    ESP_LOGI(TAG, "Firmware size: %zu bytes", content_length);

    // Download and write firmware
    const size_t buffer_size = 4096;
    uint8_t *buffer = new uint8_t[buffer_size];
    size_t total_received = 0;
    uint32_t last_update_time = 0;
    size_t last_bytes_received = 0;
    size_t speed = 0;

    while (true)
    {
        int bytes_read = http->Read(buffer, buffer_size);
        if (bytes_read <= 0)
        {
            break;
        }

        // Write to OTA partition
        err = esp_ota_write(update_handle_, buffer, bytes_read);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "esp_ota_write failed: %s", esp_err_to_name(err));
            delete[] buffer;
            esp_ota_end(update_handle_);
            http->Close();
            return false;
        }

        total_received += bytes_read;

        // Calculate speed every 100ms
        uint32_t current_time = esp_timer_get_time() / 1000;
        if (current_time - last_update_time >= 100)
        {
            speed = (total_received - last_bytes_received) * 1000 / (current_time - last_update_time);
            last_bytes_received = total_received;
            last_update_time = current_time;
        }

        // Update progress
        int progress = content_length > 0 ? (total_received * 100 / content_length) : 0;
        if (callback)
        {
            callback(progress, speed);
        }

        // Log progress periodically
        if (progress % 10 == 0)
        {
            ESP_LOGI(TAG, "Downloaded: %zu/%zu bytes (%d%%)", total_received, content_length, progress);
        }
    }

    delete[] buffer;
    http->Close();

    // Finalize OTA
    err = esp_ota_end(update_handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_end failed: %s", esp_err_to_name(err));
        return false;
    }

    // Set the new OTA partition as the one to boot from
    err = esp_ota_set_boot_partition(esp_ota_get_next_update_partition(NULL));
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "Firmware upgrade completed successfully");
    return true;
}

std::vector<int> Ota::ParseVersion(const std::string &version)
{
    std::vector<int> versionNumbers;
    std::stringstream ss(version);
    std::string segment;

    while (std::getline(ss, segment, '.'))
    {
        versionNumbers.push_back(std::stoi(segment));
    }

    return versionNumbers;
}

bool Ota::IsNewVersionAvailable(const std::string &currentVersion, const std::string &newVersion)
{
    auto current = ParseVersion(currentVersion);
    auto newVer = ParseVersion(newVersion);

    // Compare version components
    size_t minSize = std::min(current.size(), newVer.size());

    for (size_t i = 0; i < minSize; ++i)
    {
        if (newVer[i] > current[i])
        {
            return true;
        }
        else if (newVer[i] < current[i])
        {
            return false;
        }
        // If equal, continue to next component
    }

    // If all compared components are equal, the longer version is considered newer
    // For example: 1.2.3 vs 1.2.3.1 -> 1.2.3.1 is newer
    return newVer.size() > current.size();
}

std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        return "{}";
    }

    std::string hmac_hex;
#ifdef SOC_HMAC_SUPPORTED
    uint8_t hmac_result[32]; // SHA-256 输出为32字节

    // 使用Key0计算HMAC
    esp_err_t ret = esp_hmac_calculate(HMAC_KEY0, (uint8_t *)activation_challenge_.data(), activation_challenge_.size(), hmac_result);
    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "HMAC calculation failed: %s", esp_err_to_name(ret));
        return "{}";
    }

    for (size_t i = 0; i < sizeof(hmac_result); i++)
    {
        char buffer[3];
        sprintf(buffer, "%02x", hmac_result[i]);
        hmac_hex += buffer;
    }
#endif

    cJSON *payload = cJSON_CreateObject();
    cJSON_AddStringToObject(payload, "algorithm", "hmac-sha256");
    cJSON_AddStringToObject(payload, "serial_number", serial_number_.c_str());
    cJSON_AddStringToObject(payload, "challenge", activation_challenge_.c_str());
    cJSON_AddStringToObject(payload, "hmac", hmac_hex.c_str());
    auto json_str = cJSON_PrintUnformatted(payload);
    std::string json(json_str);
    cJSON_free(json_str);
    cJSON_Delete(payload);

    ESP_LOGI(TAG, "Activation payload: %s", json.c_str());
    return json;
}

esp_err_t Ota::Activate()
{
    if (!has_serial_number_ || !has_activation_challenge_)
    {
        ESP_LOGE(TAG, "Cannot activate: missing serial number or activation challenge");
        return ESP_ERR_INVALID_STATE;
    }

    // Get the activation URL from settings or use default
    Settings settings("wifi", false);
    std::string activation_url = settings.GetString("activation_url");
    if (activation_url.empty())
    {
        // Use a default activation URL or fall back to OTA URL
        activation_url = GetCheckVersionUrl() + "/activate";
    }

    auto http = SetupHttp();

    // Set the activation payload
    std::string payload = GetActivationPayload();
    http->SetContent(payload);
    http->SetHeader("Content-Length", std::to_string(payload.length()).c_str());

    // Open HTTP connection for POST request
    if (!http->Open("POST", activation_url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open activation HTTP connection, code=0x%x", last_error);
        return last_error;
    }

    // Check status code
    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to activate, status code: %d", status_code);
        http->Close();
        return status_code;
    }

    // Read response
    std::string response = http->ReadAll();
    http->Close();

    // Parse response to check if activation was successful
    cJSON *root = cJSON_Parse(response.c_str());
    if (root == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse activation response JSON");
        return ESP_ERR_INVALID_RESPONSE;
    }

