    if (cJSON_IsBool(success) && cJSON_IsTrue(success))
    {
        ESP_LOGI(TAG, "Activation successful");
        cJSON_Delete(root);
        return ESP_OK;
    }
    else
    {
        ESP_LOGE(TAG, "Activation failed");
        cJSON_Delete(root);
        return ESP_FAIL;
    }
}

