bool AudioCodec::InputData(std::vector<int16_t> &data)
{
    if (!input_enabled_ || rx_handle_ == nullptr)
    {
        return false;
    }

    // Calculate number of samples to read
    size_t sample_count = data.size();

    // Read data from I2S receive channel
    size_t bytes_read = 0;
    esp_err_t result = i2s_channel_read(rx_handle_, data.data(), sample_count * sizeof(int16_t), &bytes_read, portMAX_DELAY);

    if (result != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to read audio data from I2S: %s", esp_err_to_name(result));
        return false;
    }

    // Convert bytes read back to sample count
    size_t samples_read = bytes_read / sizeof(int16_t);

    // Apply input gain if needed
    if (input_gain_ != 1.0f)
    {
        for (size_t i = 0; i < samples_read; ++i)
        {
            float sample = static_cast<float>(data[i]) * input_gain_;
            // Clamp to int16_t range
            if (sample > 32767.0f)
                data[i] = 32767;
            else if (sample < -32768.0f)
                data[i] = -32768;
            else
                data[i] = static_cast<int16_t>(sample);
        }
    }

    // Resize vector to actual samples read (in case we read less than requested)
    data.resize(samples_read);

    return true;
}

void AudioCodec::Start()
{
    Settings settings("audio", false);
    output_volume_ = settings.GetInt("output_volume", output_volume_);
    if (output_volume_ <= 0)
    {
        ESP_LOGW(TAG, "Output volume value (%d) is too small, setting to default (10)", output_volume_);
        output_volume_ = 10;
    }

    // Initialize I2S TX channel if not already done
    if (tx_handle_ == nullptr)
    {
        i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
        ESP_ERROR_CHECK(i2s_new_channel(&tx_chan_cfg, &tx_handle_, NULL));
    }

    // Initialize I2S RX channel if not already done
    if (rx_handle_ == nullptr)
    {
        i2s_chan_config_t rx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
        ESP_ERROR_CHECK(i2s_new_channel(&rx_chan_cfg, NULL, &rx_handle_));
    }

    if (tx_handle_ != nullptr)
    {
        ESP_ERROR_CHECK(i2s_channel_enable(tx_handle_));
    }

    if (rx_handle_ != nullptr)
    {
        ESP_ERROR_CHECK(i2s_channel_enable(rx_handle_));
    }

    EnableInput(true);
    EnableOutput(true);
    ESP_LOGI(TAG, "Audio codec started");
}

