void AfeWakeWord::Stop()
{
    xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);
}

void AfeWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (afe_data_ == nullptr || data.empty()) {
        return;
    }

    // Get the required feed chunk size
    size_t feed_size = afe_iface_->get_feed_chunksize(afe_data_);

    // Process data in chunks
    size_t offset = 0;
    while (offset < data.size()) {
        size_t remaining = data.size() - offset;
        size_t chunk_size = std::min(feed_size, remaining);

        // Feed the chunk to AFE
        afe_iface_->feed(afe_data_, &data[offset], chunk_size);

        offset += chunk_size;
    }
}

