}

void AfeWakeWord::AudioDetectionTask()
{
    // Wait for detection to be started
    while (true)
    {
        // Wait until detection is enabled
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                              DETECTION_RUNNING_EVENT, 
                                              pdFALSE, 
                                              pdFALSE, 
                                              portMAX_DELAY);

        if (bits & DETECTION_RUNNING_EVENT)
        {
            // Detection is running, process audio
            while (xEventGroupGetBits(event_group_) & DETECTION_RUNNING_EVENT)
            {
                // Check if there's audio data ready from AFE
                int available_samples = afe_iface_->get_available_samples(afe_data_);

                if (available_samples >= (int)afe_iface_->get_feed_chunksize(afe_data_))
                {
                    // Get the audio data from AFE
                    size_t chunk_size = afe_iface_->get_feed_chunksize(afe_data_);
                    std::vector<int16_t> audio_chunk(chunk_size);

                    // Read the audio data
                    int read_samples = afe_iface_->fetch(afe_data_, audio_chunk.data(), chunk_size);

                    if (read_samples > 0)
                    {
                        // Store the raw PCM data for potential wake word encoding
                        StoreWakeWordData(audio_chunk.data(), read_samples);

                        // Check for wake word detection
                        int detected_index = afe_iface_->detect(afe_data_);

                        if (detected_index >= 0 && detected_index < (int)wake_words_.size())
                        {
                            // Wake word detected
                            std::string detected_word = wake_words_[detected_index];

                            // Call the callback if set
                            if (wake_word_detected_callback_)
                            {
                                wake_word_detected_callback_(detected_word);
                            }

                            // Start encoding the wake word data
                            EncodeWakeWordData();
                        }
                    }
                }
                else
                {
                    // No data available, yield to other tasks
                    vTaskDelay(10 / portTICK_PERIOD_MS);
                }
            }
        }
        else
        {
            // Detection stopped, wait for next start
            continue;
        }
    }
}

void AfeWakeWord::StoreWakeWordData(const int16_t *data, size_t samples)
{
    // store audio data to wake_word_pcm_
    wake_word_pcm_.emplace_back(std::vector<int16_t>(data, data + samples));
    // keep about 2 seconds of data, detect duration is 30ms (sample_rate == 16000, chunksize == 512)
    while (wake_word_pcm_.size() > 2000 / 30)
    {
        wake_word_pcm_.pop_front();
    }
}

void AfeWakeWord::EncodeWakeWordData()
{
    if (wake_word_pcm_.empty()) {
        return;
    }

    // Convert deque of vectors to single vector for encoding
    std::vector<int16_t> pcm_data;
    size_t total_samples = 0;

    // Calculate total samples needed
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }

    // Reserve space and copy all data
    pcm_data.reserve(total_samples);
    for (const auto& chunk : wake_word_pcm_) {
        pcm_data.insert(pcm_data.end(), chunk.begin(), chunk.end());
    }

    // Create OPUS encoder
    OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
    if (encoder == nullptr) {
        ESP_LOGE(TAG, "Failed to create OPUS encoder");
        return;
    }

    // Set encoder parameters
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(32000));
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(10));

    // Allocate buffer for encoded data
    std::vector<uint8_t> opus_buffer(1024); // Initial buffer size
    std::vector<uint8_t> encoded_data;

    // Encode the PCM data
    int frame_size = 160; // 10ms at 16kHz
    size_t total_frames = total_samples / frame_size;

    for (size_t i = 0; i < total_frames; ++i) {
        int16_t* frame_start = pcm_data.data() + (i * frame_size);
        int bytes_encoded = opus_encode(encoder, frame_start, frame_size, 
                                       opus_buffer.data(), opus_buffer.size());

        if (bytes_encoded > 0) {
            encoded_data.insert(encoded_data.end(), opus_buffer.begin(), 
                              opus_buffer.begin() + bytes_encoded);
        }
    }

    // Clean up encoder
    opus_encoder_destroy(encoder);

    // Store encoded data in queue
    std::lock_guard<std::mutex> lock(wake_word_mutex_);
    wake_word_opus_.emplace_back(std::move(encoded_data));

    // Notify waiting threads
    wake_word_cv_.notify_one();
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data available or we have an empty packet (end marker)
    wake_word_cv_.wait(lock, [this] { 
        return !wake_word_opus_.empty() || 
               (wake_word_opus_.size() == 1 && wake_word_opus_.front().empty()); 
    });

    if (wake_word_opus_.empty()) {
        return false;
    }

    // Check if this is the end marker (empty packet)
    if (wake_word_opus_.front().empty()) {
        wake_word_opus_.pop_front();
        return false; // No more data
    }

    // Return the first packet
    opus = std::move(wake_word_opus_.front());
    wake_word_opus_.pop_front();

    return true;
}

