void SetOutputState(uint8_t bit, uint8_t level)
{
    uint8_t port = 0;
    uint8_t data = 0;

    // Determine which port (0 or 1) the bit belongs to
    if (bit < 8) {
        port = 0x02;  // Port 0 output register
        data = ReadReg(0x02);  // Read current value
    } else {
        port = 0x03;  // Port 1 output register
        data = ReadReg(0x03);  // Read current value
    }

    // Set or clear the specific bit
    if (level) {
        data |= (1 << (bit % 8));  // Set bit
    } else {
        data &= ~(1 << (bit % 8)); // Clear bit
    }

    // Write back to the appropriate register
    WriteReg(port, data);
}

