FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : frequency_(frequency), window_size_(window_size)
{
    frequency_bin_ = std::floor(frequency_ * static_cast<float>(window_size_));

    // Calculate Goertzel algorithm coefficients
    float omega = 2.0f * M_PI * frequency_;
    float sine = std::sin(omega);
    float cosine = std::cos(omega);
    float coeff = 2.0f * cosine;

    filter_coefficient_ = coeff;
    cos_coefficient_ = cosine;
    sin_coefficient_ = sine;

    Reset();
}

void FrequencyDetector::Reset()
{
    // Reset state buffer to initial state (two zeros)
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::ProcessSample(float sample)
{
    if (state_buffer_.size() < 2)
    {
        // Initialize buffer if needed
        state_buffer_.resize(2);
        state_buffer_[0] = 0.0f;
        state_buffer_[1] = 0.0f;
    }

    // Apply Goertzel algorithm recursion
    float s_n = filter_coefficient_ * state_buffer_[1] - state_buffer_[0] + sample;

    // Shift the state buffer
    state_buffer_[0] = state_buffer_[1];
    state_buffer_[1] = s_n;
}

float FrequencyDetector::GetAmplitude() const
{
    if (state_buffer_.size() < 2)
    {
        return 0.0f;
    }

    // Get the last two states (S[-1] and S[0])
    float s_minus_1 = *(state_buffer_.rbegin() + 1); // Second to last element
    float s_current = *(state_buffer_.rbegin());    // Last element

    // Calculate amplitude using the Goertzel algorithm formula
    // Amplitude = sqrt(S[-1]^2 + S[0]^2 - 2*S[-1]*S[0]*cos(omega))
    // Where omega = 2*pi*f
    float amplitude = std::sqrt(s_minus_1 * s_minus_1 + s_current * s_current - 
                              2.0f * s_minus_1 * s_current * cos_coefficient_);

    return amplitude;
}

// AudioSignalProcessor implementation
AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency,
                                           size_t bit_rate, size_t window_size)
    : input_buffer_size_(window_size), output_sample_count_(0)
{
    if (sample_rate % bit_rate != 0)
    {
        // On ESP32 we can continue execution, but log the error
        ESP_LOGW(kLogTag, "Sample rate %zu is not divisible by bit rate %zu", sample_rate, bit_rate);
    }

    float normalized_mark_freq = static_cast<float>(mark_frequency) / static_cast<float>(sample_rate);
    float normalized_space_freq = static_cast<float>(space_frequency) / static_cast<float>(sample_rate);

    mark_detector_ = std::make_unique<FrequencyDetector>(normalized_mark_freq, window_size);
    space_detector_ = std::make_unique<FrequencyDetector>(normalized_space_freq, window_size);

    samples_per_bit_ = sample_rate / bit_rate; // Number of samples per bit

    // Initialize the input buffer
    input_buffer_.clear();
    input_buffer_.resize(window_size, 0.0f);
}

std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float> &samples)
{
    std::vector<float> probabilities;
    probabilities.reserve(samples.size());

    for (float sample : samples)
    {
        // Process the sample with both frequency detectors
        mark_detector_->ProcessSample(sample);
        space_detector_->ProcessSample(sample);

        // Get amplitudes from both detectors
        float mark_amplitude = mark_detector_->GetAmplitude();
        float space_amplitude = space_detector_->GetAmplitude();

        // Determine which frequency is stronger
        // Return probability: 1.0 if mark frequency detected, 0.0 if space frequency detected
        float probability = (mark_amplitude > space_amplitude) ? 1.0f : 0.0f;

        probabilities.push_back(probability);
    }

    return probabilities;
}

