bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold)
{
    for (float probability : probabilities)
    {
        // Convert probability to bit (0 or 1)
        uint8_t bit = (probability > threshold) ? 1 : 0;

        // Update identifier buffer with new bit
        identifier_buffer_.push_back(bit);
        if (identifier_buffer_.size() > identifier_buffer_size_)
        {
            identifier_buffer_.pop_front();
        }

        switch (current_state_)
        {
            case DataReceptionState::kInactive:
                // Check if we've detected the start of transmission
                if (identifier_buffer_.size() >= start_of_transmission_.size())
                {
                    bool start_match = true;
                    for (size_t i = 0; i < start_of_transmission_.size(); ++i)
                    {
                        if (identifier_buffer_[identifier_buffer_.size() - start_of_transmission_.size() + i] != start_of_transmission_[i])
                        {
                            start_match = false;
                            break;
                        }
                    }

                    if (start_match)
                    {
                        current_state_ = DataReceptionState::kReceivingData;
                        bit_buffer_.clear(); // Clear previous data
                    }
                }
                break;

            case DataReceptionState::kReceivingData:
                // Add bit to data buffer
                bit_buffer_.push_back(bit);

                // Check if we've reached maximum buffer size
                if (bit_buffer_.size() >= max_bit_buffer_size_)
                {
                    // Buffer overflow - reset
                    current_state_ = DataReceptionState::kInactive;
                    bit_buffer_.clear();
                    break;
                }

                // Check if we've detected the end of transmission
                if (identifier_buffer_.size() >= end_of_transmission_.size())
                {
                    bool end_match = true;
                    for (size_t i = 0; i < end_of_transmission_.size(); ++i)
                    {
                        if (identifier_buffer_[identifier_buffer_.size() - end_of_transmission_.size() + i] != end_of_transmission_[i])
                        {
                            end_match = false;
                            break;
                        }
                    }

                    if (end_match)
                    {
                        // End of transmission detected - process data
                        current_state_ = DataReceptionState::kInactive;

                        // Convert bits to bytes
                        std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);

                        if (bytes.empty())
                        {
                            break;
                        }

                        // If checksum validation is enabled, verify it
                        if (enable_checksum_validation_)
                        {
                            // Extract data without checksum byte (last byte)
                            std::string data_string(bytes.begin(), bytes.end() - 1);
                            uint8_t calculated_checksum = CalculateChecksum(data_string);
                            uint8_t received_checksum = bytes.back();

                            if (calculated_checksum != received_checksum)
                            {
                                // Checksum mismatch - ignore this data
                                break;
                            }
                        }

                        // Convert to string and store
                        decoded_text = std::string(bytes.begin(), bytes.end() - (enable_checksum_validation_ ? 1 : 0));
                        return true; // Complete data received
                    }
                }
                break;

            default:
                break;
        }
    }

    return false; // No complete data received yet
}

std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
{
    std::vector<uint8_t> bytes;

    // Ensure number of bits is a multiple of 8
    size_t complete_bytes_count = bits.size() / 8;
    bytes.reserve(complete_bytes_count);

    for (size_t i = 0; i < complete_bytes_count; ++i)
    {
        uint8_t byte_value = 0;
        for (size_t j = 0; j < 8; ++j)
        {
            byte_value |= bits[i * 8 + j] << (7 - j);
        }
        bytes.push_back(byte_value);
    }

    return bytes;
}

