void Backlight::RestoreBrightness()
{
    Settings settings("display", true);
    int saved_brightness = settings.GetInt("brightness", 0);

    // If no brightness setting exists, use default (0)
    if (saved_brightness < 0 || saved_brightness > 100) {
        saved_brightness = 0;
    }

    SetBrightness(saved_brightness, false);
}

void Backlight::SetBrightness(uint8_t brightness, bool transition)
{
    // Clamp brightness to valid range
    if (brightness > 100)
        brightness = 100;

    // If we're not transitioning or already at target, set immediately
    if (!transition || brightness == target_brightness_)
    {
        brightness_ = brightness;
        target_brightness_ = brightness;
        step_ = 0;
        SetBrightnessImpl(brightness);
        return;
    }

    // Set up for smooth transition
    target_brightness_ = brightness;

    // Calculate step size for smooth transition
    // Assuming we want to reach target in about 100ms with 5ms updates
    int steps = 20; // 100ms / 5ms = 20 steps

    // Calculate step direction and magnitude
    if (brightness > brightness_)
    {
        step_ = (brightness - brightness_) / steps;
        if (step_ == 0) step_ = 1; // Ensure we make progress
    }
    else
    {
        step_ = -(brightness_ - brightness) / steps;
        if (step_ == 0) step_ = -1; // Ensure we make progress
    }

    // Start the transition timer if not already running
    if (transition_timer_ != nullptr && !esp_timer_is_active(transition_timer_))
    {
        esp_timer_start_periodic(transition_timer_, 5 * 1000);
    }
}

void Backlight::OnTransitionTimer()
{
    // Update brightness value
    brightness_ += step_;

    // Check if transition is complete
    if ((step_ > 0 && brightness_ >= target_brightness_) || 
        (step_ < 0 && brightness_ <= target_brightness_))
    {
        // Ensure we reach the exact target value
        brightness_ = target_brightness_;

        // Stop the timer as transition is complete
        if (transition_timer_ != nullptr)
        {
            esp_timer_stop(transition_timer_);
        }
    }

    // Apply the new brightness to hardware
    SetBrightnessImpl(brightness_);
}

