void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    // Only proceed if WiFi is initialized and available
    auto &wifi_manager = WifiManager::GetInstance();
    if (!wifi_manager.IsInitialized()) {
        return;
    }

    // Convert PowerSaveLevel enum to ESP-IDF power save mode
    wifi_ps_type_t ps_mode = WIFI_PS_NONE;

    switch (level) {
        case PowerSaveLevel::NONE:
            ps_mode = WIFI_PS_NONE;
            break;
        case PowerSaveLevel::LIGHT:
            ps_mode = WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::STANDARD:
            ps_mode = WIFI_PS_MAX_MODEM;
            break;
        default:
            ps_mode = WIFI_PS_NONE;
            break;
    }

    // Apply the power save configuration
    esp_err_t err = esp_wifi_set_ps(ps_mode);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to set power save level: %s", esp_err_to_name(err));
    } else {
        ESP_LOGD(TAG, "Power save level set to: %d", static_cast<int>(level));
    }
}

