bool MqttProtocol::StartMqttClient(bool report_error)
{
    // Check if MQTT client is already initialized
    if (mqtt_ != nullptr)
    {
        if (mqtt_->IsConnected())
        {
            return true;
        }
        else
        {
            // Clean up existing client if not connected
            mqtt_.reset();
        }
    }

    // Get MQTT configuration from settings
    auto &settings = Settings::GetInstance();
    std::string broker_url = settings.GetMqttBrokerUrl();
    std::string username = settings.GetMqttUsername();
    std::string password = settings.GetMqttPassword();
    std::string client_id = settings.GetDeviceId();

    // Validate required parameters
    if (broker_url.empty())
    {
        ESP_LOGE(TAG, "MQTT broker URL is empty");
        if (report_error)
        {
            SetError(Lang::Strings::MQTT_CONNECTION_FAILED);
        }
        return false;
    }

    // Create MQTT client instance
    auto network = Board::GetInstance().GetNetwork();
    mqtt_ = network->CreateMqtt();

    if (mqtt_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create MQTT client");
        if (report_error)
        {
            SetError(Lang::Strings::MQTT_CONNECTION_FAILED);
        }
        return false;
    }

    // Configure MQTT client
    mqtt_->SetClientId(client_id);
    mqtt_->SetUsername(username);
    mqtt_->SetPassword(password);

    // Set up connection callback
    mqtt_->OnConnected([this]()
                       {
        ESP_LOGI(TAG, "MQTT connected successfully");
        // Subscribe to required topics after connection
        // This would typically subscribe to control topics
        // For now, we'll just set the connected flag
        });

    mqtt_->OnDisconnected([this]()
                          {
        ESP_LOGI(TAG, "MQTT disconnected");
        // Schedule reconnection if needed
        if (alive_)
        {
            esp_timer_start_once(reconnect_timer_, 5 * 1000 * 1000); // 5 seconds
        }
        });

    mqtt_->OnMessage([this](const std::string &topic, const std::string &payload)
                     {
        // Handle incoming MQTT messages
        // This would process control commands, etc.
        ESP_LOGD(TAG, "MQTT message received on topic: %s", topic.c_str());
        });

    // Attempt to connect
    ESP_LOGI(TAG, "Connecting to MQTT broker: %s", broker_url.c_str());
    bool connected = mqtt_->Connect(broker_url);

    if (!connected)
    {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error)
        {
            SetError(Lang::Strings::MQTT_CONNECTION_FAILED);
        }
        mqtt_.reset(); // Clean up on failure
        return false;
    }

    // Connection successful
    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

bool MqttProtocol::SendText(const std::string &text)
