}

bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (udp_ == nullptr || !udp_->IsConnected()) {
        ESP_LOGE(TAG, "UDP channel is not opened");
        return false;
    }

    // Prepare the audio packet header and data
    // Format: |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|payload payload_len|

    // Create the packet buffer
    std::vector<uint8_t> packet_buffer;
    packet_buffer.reserve(20 + packet->payload.size()); // Header + payload

    // Add type (0x01 for audio packet)
    packet_buffer.push_back(0x01);

    // Add flags (0x00 for now)
    packet_buffer.push_back(0x00);

    // Add payload length (2 bytes, big endian)
    uint16_t payload_len = packet->payload.size();
    packet_buffer.push_back((payload_len >> 8) & 0xFF);
    packet_buffer.push_back(payload_len & 0xFF);

    // Add ssrc (4 bytes, big endian) - using 0 for now
    uint32_t ssrc = 0;
    packet_buffer.push_back((ssrc >> 24) & 0xFF);
    packet_buffer.push_back((ssrc >> 16) & 0xFF);
    packet_buffer.push_back((ssrc >> 8) & 0xFF);
    packet_buffer.push_back(ssrc & 0xFF);

    // Add timestamp (4 bytes, big endian)
    uint32_t timestamp = packet->timestamp;
    packet_buffer.push_back((timestamp >> 24) & 0xFF);
    packet_buffer.push_back((timestamp >> 16) & 0xFF);
    packet_buffer.push_back((timestamp >> 8) & 0xFF);
    packet_buffer.push_back(timestamp & 0xFF);

    // Add sequence number (4 bytes, big endian)
    uint32_t sequence = local_sequence_++;
    packet_buffer.push_back((sequence >> 24) & 0xFF);
    packet_buffer.push_back((sequence >> 16) & 0xFF);
    packet_buffer.push_back((sequence >> 8) & 0xFF);
    packet_buffer.push_back(sequence & 0xFF);

    // Add encrypted payload
    if (packet->payload.size() > 0) {
        // Encrypt the payload
        size_t encrypted_size = packet->payload.size();
        size_t nc_off = 0;
        uint8_t stream_block[16] = {0};

        // Use nonce from aes_nonce_
        std::vector<uint8_t> nonce_data = aes_nonce_;
        nonce_data.resize(16); // Ensure it's exactly 16 bytes

        // Encrypt the payload
        std::vector<uint8_t> encrypted_payload(encrypted_size);
        int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_size, &nc_off, nonce_data.data(), stream_block, 
                                       (const uint8_t*)packet->payload.data(), encrypted_payload.data());

        if (ret != 0) {
            ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
            return false;
        }

        // Append encrypted payload to buffer
        packet_buffer.insert(packet_buffer.end(), encrypted_payload.begin(), encrypted_payload.end());
    }

    // Send the packet via UDP
    if (!udp_->Send((const char*)packet_buffer.data(), packet_buffer.size())) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        return false;
    }

    return true;
}

void MqttProtocol::CloseAudioChannel()
{
    std::lock_guard<std::mutex> lock(channel_mutex_);

    if (udp_ != nullptr) {
        udp_.reset();
    }

    if (aes_ctx_.MBEDTLS_PRIVATE(cipher_info) != nullptr) {
        mbedtls_aes_free(&aes_ctx_);
    }
}

