void MqttProtocol::ParseServerHello(const cJSON *root)
{
    // Parse server hello response
    cJSON *session_id = cJSON_GetObjectItem(root, "session_id");
    if (session_id != nullptr && cJSON_IsString(session_id))
    {
        session_id_ = session_id->valuestring;
    }

    cJSON *server_sample_rate = cJSON_GetObjectItem(root, "sample_rate");
    if (server_sample_rate != nullptr && cJSON_IsNumber(server_sample_rate))
    {
        server_sample_rate_ = server_sample_rate->valuedouble;
    }

    cJSON *server_frame_duration = cJSON_GetObjectItem(root, "frame_duration");
    if (server_frame_duration != nullptr && cJSON_IsNumber(server_frame_duration))
    {
        server_frame_duration_ = server_frame_duration->valuedouble;
    }

    cJSON *udp_server = cJSON_GetObjectItem(root, "udp_server");
    if (udp_server != nullptr && cJSON_IsString(udp_server))
    {
        udp_server_ = udp_server->valuestring;
    }

    cJSON *udp_port = cJSON_GetObjectItem(root, "udp_port");
    if (udp_port != nullptr && cJSON_IsNumber(udp_port))
    {
        udp_port_ = udp_port->valueint;
    }

    cJSON *aes_key = cJSON_GetObjectItem(root, "aes_key");
    if (aes_key != nullptr && cJSON_IsString(aes_key))
    {
        std::string key_str = DecodeHexString(aes_key->valuestring);
        if (key_str.length() == 16)
        {
            memcpy(aes_key_.data(), key_str.data(), 16);
        }
    }

    cJSON *aes_nonce = cJSON_GetObjectItem(root, "aes_nonce");
    if (aes_nonce != nullptr && cJSON_IsString(aes_nonce))
    {
        std::string nonce_str = DecodeHexString(aes_nonce->valuestring);
        if (nonce_str.length() == 16)
        {
            aes_nonce_ = nonce_str;
        }
    }

    // Initialize AES context
    mbedtls_aes_init(&aes_ctx_);
    mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char *)aes_key_.data(), 128);

    // Set the event bit to indicate server hello received
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

static inline uint8_t CharToHex(char c)
{
    if (c >= '0' && c <= '9') {
        return c - '0';
    }
    if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    }
    if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    }
    return 0; // Invalid hex character
}

std::string MqttProtocol::DecodeHexString(const std::string &hex_string)
{
    std::string result;
    result.reserve(hex_string.length() / 2);

    for (size_t i = 0; i < hex_string.length(); i += 2)
    {
        // Handle cases where there might be an odd number of hex characters
        if (i + 1 >= hex_string.length())
        {
            break;
        }

        char high = hex_string[i];
        char low = hex_string[i + 1];

        // Convert hex characters to their numeric values
        uint8_t high_val = CharToHex(high);
        uint8_t low_val = CharToHex(low);

        // Combine high and low nibbles into a single byte
        uint8_t byte_val = (high_val << 4) | low_val;

        result.push_back(static_cast<char>(byte_val));
    }

    return result;
}

