bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    if (version_ == 2)
    {
        // For version 2, use BinaryProtocol2 format
        std::string serialized;
        serialized.resize(sizeof(BinaryProtocol2) + packet->payload.size());
        auto bp2 = (BinaryProtocol2 *)serialized.data();
        bp2->version = htons(2);
        bp2->type = htons(1); // Assuming type 1 for audio data
        bp2->timestamp = htonl(packet->timestamp);
        bp2->payload_size = htonl(packet->payload.size());
        memcpy(bp2->payload, packet->payload.data(), packet->payload.size());

        return websocket_->Send(serialized.data(), serialized.size(), true);
    }
    else if (version_ == 3)
    {
        // For version 3, use BinaryProtocol3 format
        std::string serialized;
        serialized.resize(sizeof(BinaryProtocol3) + packet->payload.size());
        auto bp3 = (BinaryProtocol3 *)serialized.data();
        bp3->type = 1; // Assuming type 1 for audio data
        bp3->reserved = 0;
        bp3->payload_size = htons(packet->payload.size());
        memcpy(bp3->payload, packet->payload.data(), packet->payload.size());

        return websocket_->Send(serialized.data(), serialized.size(), true);
    }
    else
    {
        // For other versions, send raw payload
        return websocket_->Send(packet->payload.data(), packet->payload.size(), true);
    }
}

bool WebsocketProtocol::SendText(const std::string &text)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    return websocket_->Send(text.data(), text.size(), false);
}

