std::string WebsocketProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "type", "hello");

    // Add device information
    cJSON_AddStringToObject(root, "device_id", SystemInfo::GetMacAddress().c_str());
    cJSON_AddStringToObject(root, "client_id", Board::GetInstance().GetUuid().c_str());

    // Add audio parameters
    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);  // Default sample rate
    cJSON_AddNumberToObject(audio_params, "frame_duration", 20);  // Default frame duration in ms
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Add protocol version
    cJSON_AddNumberToObject(root, "protocol_version", version_);

    char *json_string = cJSON_Print(root);
    std::string result = json_string;
    cJSON_Free(json_string);
    cJSON_Delete(root);

    return result;
}

void WebsocketProtocol::ParseServerHello(const cJSON *root)
{
    // Parse server version
    auto version = cJSON_GetObjectItem(root, "version");
    if (cJSON_IsNumber(version)) {
        server_version_ = version->valuedouble;
    }

    // Parse server features
    auto features = cJSON_GetObjectItem(root, "features");
    if (cJSON_IsObject(features)) {
        // Parse AEC support
        auto aec = cJSON_GetObjectItem(features, "aec");
        if (cJSON_IsBool(aec)) {
            server_aec_supported_ = cJSON_IsTrue(aec);
        }

        // Parse MCP support
        auto mcp = cJSON_GetObjectItem(features, "mcp");
        if (cJSON_IsBool(mcp)) {
            server_mcp_supported_ = cJSON_IsTrue(mcp);
        }
    }

    // Parse audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params)) {
        // Parse sample rate
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valuedouble;
        }

        // Parse frame duration
        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valuedouble;
        }

        // Parse format
        auto format = cJSON_GetObjectItem(audio_params, "format");
        if (cJSON_IsString(format)) {
            server_audio_format_ = format->valuestring;
        }
    }

    // Signal that we've received the server hello
    xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
}
